        const updatedEvents = data.events?.map((event)=>({
                ...event,
                isRegistered: "undefined" !== 'undefined' && localStorage.getItem(`registered_${event._id}`) === 'true'
            }));
        return {
            events: updatedEvents || data.events || [],
            totalItems: data.totalItems || 0,
            totalPages: data.totalPages || Math.ceil((data.totalItems || 0) / eventsPerPage)
        };
